public class Out {
    public static float out(float t, float a, float p) {
            if (t == 0) {
                return 0;
            }
            if (t >= 1) {
                return 1;
            }
            if (p == 0) {
                p = 0.3f;
            }
            float s;
            if (a == 0 || a < 1) {
                a = 1;
                s = p / 4;
            } else {
                s = (float) (p / (2 * Math.PI) * Math.asin(1 / a));
            }
            return (float) (a * Math.pow(2, -10 * t) * Math.sin((t - s) * (2 * Math.PI) / p) + 1);
        }
