public class IsLetter {
    public static boolean isLetter(char c) {
            if (c == '$' || c == '_' || c == '@') {
                return true;
            }
            if (c >= 'a' && c <= 'z') {
                return true;
            }
            if (c >= 'A' && c <= 'Z') {
                return true;
            }
            return false;
        }
