public class ExcludeReg {
    public static boolean excludeReg(int reg) {
            // These registers are used by the yellow pekoe assembler
            if (reg == 14)
                return true;
            if (reg == 15)
                return true;
            if (reg == 24)
                return true;
            if (reg == 25)
                return true;
            // These are the kernel registers
            if (reg == 26)
                return true;
            if (reg == 27)
                return true;
            // We exlude the GP since the C code we call into assumes GP has
            // a proper value
            // GP, SP, FP, LR
            if (reg == 28)
                return true;
            if (reg == 29)
                return true;
            if (reg == 30)
                return true;
            if (reg == 31)
                return true;
            return false;
        }
