public class SuitablePower2 {
    public static int suitablePower2(int s) {
            //		return 128;
            if (s > 380)
                return 512;
            else if (s > 192)
                return 256;
            else if (s > 96)
                return 128;
            else if (s > 48)
                return 64;
            else if (s > 24)
                return 32;
            else if (s > 12)
                return 16;
            else if (s > 6)
                return 8;
            else
                return 4;
        }
