public class Power {
    public double power(double x, int n) {
            switch(n) {
                case 0:
                    x = 1.0;
                    break;
                case 1:
                    break;
                case 2:
                    x *= x;
                    break;
                case 3:
                    x *= x * x;
                    break;
                case 4:
                    x *= x * x * x;
                    break;
                case 5:
                    x *= x * x * x * x;
                    break;
                case 6:
                    x *= x * x * x * x * x;
                    break;
                case 7:
                    x *= x * x * x * x * x * x;
                    break;
                case 8:
                    x *= x * x * x * x * x * x * x;
                    break;
                default:
                    {
                        int bitMask = n;
                        double evenPower = x;
                        double result;
                        if ((bitMask & 1) != 0)
                            result = x;
                        else
                            result = 1;
                        bitMask >>>= 1;
                        while (bitMask != 0) {
                            evenPower *= evenPower;
                            if ((bitMask & 1) != 0)
                                result *= evenPower;
                            bitMask >>>= 1;
                        }
                        // end while
                        x = result;
                    }
            }
            return x;
        }
