public class Direction {
    public static int direction(int srcX, int srcY, int destX, int destY) {
            int dx = destX - srcX, dy = destY - srcY;
            // a lot of cases that have to be considered here ... is there a more
            // sophisticated (and quick!) way?
            if (dx < 0) {
                if (dy < 0) {
                    if (dx < dy)
                        return 11;
                    else if (dx > dy)
                        return 9;
                    else
                        // dx == dy
                        return 10;
                } else if (dy > 0) {
                    if (-dx < dy)
                        return 15;
                    else if (-dx > dy)
                        return 13;
                    else
                        // -dx == dy
                        return 14;
                } else {
                    // dy == 0
                    return 12;
                }
            } else if (dx > 0) {
                if (dy < 0) {
                    if (dx < -dy)
                        return 7;
                    else if (dx > -dy)
                        return 5;
                    else
                        // dx == -dy
                        return 6;
                } else if (dy > 0) {
                    if (dx < dy)
                        return 1;
                    else if (dx > dy)
                        return 3;
                    else
                        // dx == dy
                        return 2;
                } else {
                    // dy == 0
                    return 4;
                }
            } else {
                // dx == 0
                if (dy < 0) {
                    return 8;
                } else if (dy > 0) {
                    return 0;
                } else {
                    // dy == 0
                    // src and dest are the same
                    return -1;
                }
            }
        }
