public class IsAlpha {
    public static boolean isAlpha(char c) {
            // "$", // for absolute references in the spreadsheet
            if (c >= 'a' && c <= 'z') {
                return true;
            } else if (c >= 'A' && c <= 'Z') {
                return true;
            } else if (c == '\'') {
                return true;
            } else if (c == '?') {
                return true;
            } else if (c == 0x00b7) {
                // middle dot (for Catalan).
                return true;
            } else if (c == 0x00b0) {
                // degree symbol).
                return true;
            } else if (c >= 0x00c0 && c <= 0x00d6) {
                //accentuated letters.
                return true;
            } else if (c >= 0x00d8 && c <= 0x01bf) {
                //accentuated letters.
                return true;
            } else if (c >= 0x01c4 && c <= 0x02a8) {
                //accentuated letters.
                return true;
            } else if (c >= 0x0391 && c <= 0x03f3) {
                // Greek.
                return true;
            } else if (c >= 0x0401 && c <= 0x0481) {
                // Cyrillic.
                return true;
            } else if (c >= 0x0490 && c <= 0x04f9) {
                // Cyrillic.
                return true;
            } else if (c >= 0x0531 && c <= 0x1ffc) {
                // a lot of signs (Arabic, accentuated, ...).
                return true;
            } else if (c >= 0x3041 && c <= 0x3357) {
                // Asian letters.
                return true;
            } else if (c >= 0x4e00 && c <= 0xd7a3) {
                // Asian letters.
                return true;
            } else if (c >= 0xf71d && c <= 0xfa2d) {
                // Asian letters.
                return true;
            } else if (c >= 0xfb13 && c <= 0xfdfb) {
                // Armenian, Hebrew, Arabic.
                return true;
            } else if (c >= 0xfe80 && c <= 0xfefc) {
                // Arabic.
                return true;
            } else if (c >= 0xff66 && c <= 0xff9d) {
                // Katakana.
                return true;
            } else if (c >= 0xffa1 && c <= 0xffdc) {
                // Hangul.
                return true;
            }
            return false;
            //return ( (c>='a' && c<='z') || (c>='A' && c<='Z') || (c == '\'') || unicodeVariableChars.indexOf(c) != -1);
        }
