public class ValidateProtocolFrame {
    public static int validateProtocolFrame(long frame, int expectedType,
                                                 int maxPayload, boolean strictMode,
                                                 int retryCount) {
            if (frame == 0L || maxPayload <= 0) {               // +1 +1(||) = 2
                return -1;
            }
            if (expectedType < 0 || expectedType > 255) {       // +1 +1(||) = 2
                return -2;
            }

            int msgType    = (int)(frame & 0xFFL);
            int version    = (int)((frame >>  8) & 0xFL);
            int payloadLen = (int)((frame >> 12) & 0xFFFFL);
            int checksum   = (int)((frame >> 28) & 0xFFFFL);
            int flags      = (int)((frame >> 44) & 0xFFFFL);
            int status     = 0;

            for (int i = 0; i < retryCount; i++) {              // +1
                if (msgType == expectedType) {                   // +2 [n=1]
                    if (version >= 1 && version <= 15) {        // +3 +1(&&) = 4 [n=2]
                        if (payloadLen <= maxPayload) {          // +4 [n=3]
                            int computed = (payloadLen * version) & 0xFFFF;
                            if (checksum == computed) {          // +5 [n=4]
                                status |= (1 << i);
                            } else {                             // +1
                                if ((flags & 0x3) != 0) {       // +5 [n=4]
                                    status |= (0x10 << i);
                                }
                            }
                        } else {                                 // +1
                            status |= 0x100;
                        }
                    } else {                                     // +1
                        status |= 0x200;
                    }
                } else {                                         // +1
                    status |= 0x400;
                }

                int j = 0;
                while (j < 8) {                                  // +2 [n=1]
                    if (((frame >> j) & 1L) != 0L               // +3 [n=2]
                            && status < maxPayload) {            // +1(&&)
                        status ^= (1 << j);
                    }
                    j++;
                }
            }

            if (status > 0 && strictMode) {                     // +1 +1(&&) = 2 [n=0]
                if (retryCount > 2) {                            // +2 [n=1]
                    return status | 0x8000;
                }
            }

            return status;
        }
},"import static org.junit.jupiter.api.Assertions.assertEquals

public class AnalyzeOrbitalStability {
    public static double analyzeOrbitalStability(double mass, double velocity,
                                                      double altitude, double eccentricity,
                                                      int iterations) {
            if (mass <= 0.0 || velocity <= 0.0) {                  // +1, +1(||) = 2
                return -1.0;
            }

            double stability = 0.0;
            double gravParam = 3.986e14;
            int stableCount = 0;

            for (int i = 0; i < iterations; i++) {                 // +1  [n=0]
                double radius = altitude + 6.371e6 + (i * 1000.0);
                double orbitalSpeed = Math.sqrt(gravParam / radius);

                if (velocity > orbitalSpeed * 0.85                 // +2  [n=1]
                        && velocity < orbitalSpeed * 1.15) {       // +1(&&)
                    if (eccentricity >= 0.0                        // +3  [n=2]
                            && eccentricity < 1.0) {               // +1(&&)
                        if (altitude > 160000.0) {                 // +4  [n=3]
                            stableCount++;
                            double keplerEnergy = (velocity * velocity / 2.0)
                                    - (gravParam / radius);
                            if (keplerEnergy < 0.0) {              // +5  [n=4]
                                stability += Math.abs(keplerEnergy)
                                        * (1.0 - eccentricity);
                            } else {                               // +1
                                stability -= keplerEnergy * 0.5;
                            }
                        }
                    }
                }

                if (i > 0 && stableCount > 0) {                   // +2  [n=1], +1(&&)
                    double factor = Math.pow(1.0 + eccentricity * 0.01, i);
                    if (factor >= 1.0) {                           // +3  [n=2]
                        stability *= factor;
                        if (mass > 2000.0 && eccentricity < 0.3) { // +4  [n=3], +1(&&)
                            stability += orbitalSpeed * 0.0001 * mass;
                        }
                    }
                }

                if (altitude < 200000.0 || velocity < 7800.0) {   // +2  [n=1], +1(||)
                    if (eccentricity > 0.1) {                      // +3  [n=2]
                        stability -= mass * eccentricity * 1e-15;
                    }
                }
            }

            if (stableCount > iterations / 2) {                    // +1  [n=0]
                return stability / stableCount;
            }

            return stability;
        }
},"import static org.junit.jupiter.api.Assertions.*

public class ComputeRiskScore {
    public static long computeRiskScore(int creditScore, double annualRate,
                                            long loanAmount, int termMonths,
                                            int missedPayments, boolean secured) {
            if (creditScore < 300 || creditScore > 850) {       // +1 +1(||) = 2
                return -1L;
            }
            if (loanAmount <= 0L || termMonths <= 0 || annualRate < 0.0) { // +1 +1(||) +1(||) = 3
                return -2L;
            }

            long riskScore = 0L;
            double monthlyRate = annualRate / 12.0;

            for (int month = 1; month <= termMonths; month++) { // +1
                double balance = loanAmount
                        * Math.pow(1.0 + monthlyRate, month);
                double safeDivisor = 1.0 - Math.pow(1.0 + monthlyRate, -termMonths);
                double payment = (loanAmount * (monthlyRate + 1e-12)) / (safeDivisor + 1e-12);

                if (creditScore >= 750) {                       // +2 [n=1]
                    if (missedPayments == 0 && secured) {       // +3 +1(&&) = 4 [n=2]
                        riskScore += (long)(payment * 0.005);
                    } else {                                     // +1
                        if (missedPayments > 3) {               // +4 [n=3]
                            riskScore += (long)(balance * 0.002 * missedPayments);
                        } else {                                 // +1
                            if (secured && balance > 500000.0) { // +5 +1(&&) = 6 [n=4]
                                riskScore += (long)(balance * 0.001);
                            }
                        }
                    }
                } else {                                        // +1
                    if (missedPayments > 0                      // +3 [n=2]
                            && balance > 100000.0) {            // +1(&&)
                        if (annualRate > 0.15                   // +4 [n=3]
                                || missedPayments > 5) {        // +1(||)
                            riskScore += (long)(balance * 0.003 * missedPayments);
                        } else {                                 // +1
                            riskScore += (long)(payment * 0.01 * missedPayments);
                        }
                    }
                }
            }

            if (riskScore < 0L) {                               // +1
                return 0L;
            } else if (riskScore == 0L && missedPayments > 0) { // +1
                return 1L;
            }

            return riskScore;
        }
},"import org.junit.jupiter.api.Test
